import asyncioimport pytestfrom dotenv import load_dotenvfrom ragas import SingleTurnSamplefrom ragas.metrics._context_recall import LLMContextRecallfrom llmeval.utils import get_llm_response, load_test_dataload_dotenv()filename = "tests/fixtures/parametrization_data.json"@pytest.mark.asyncio@pytest.mark.parametrize(    "get_data",    load_test_data(filename),    indirect=True)async def test_context_recall_parametrized(llm_wrapper, get_data):    # Context Recall does not need response. It needs ground truth (reference)    context_recall = LLMContextRecall(llm=llm_wrapper)    print("Computing context recall score...", flush=True)    try:        score = await asyncio.wait_for(            context_recall.single_turn_ascore(get_data),            timeout=30,        )    except asyncio.TimeoutError as exc:        pytest.fail("Timed out waiting for context precision score (30s)")    print(f"The score is: {score}")    # assertions    assert score is not None    assert 0 <= score <= 1    assert score > 0.7@pytest.fixturedef get_data(request):    test_data = request.param    response_dict = get_llm_response(test_data)    sample = SingleTurnSample(        user_input=test_data["question"],        retrieved_contexts=[            response_dict["retrieved_docs"][0]["page_content"],            response_dict["retrieved_docs"][1]["page_content"],            response_dict["retrieved_docs"][2]["page_content"],            response_dict["retrieved_docs"][3]["page_content"]        ],        reference=test_data["reference"]    )    return sample